import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.DEqXEGcv.js";const b=JSON.parse('{"title":"Backup & Restore","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/guide/backup.md","filePath":"en/docs/guide/backup.md"}'),s={name:"en/docs/guide/backup.md"};function i(n,t,d,c,l,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="backup-restore" tabindex="-1">Backup &amp; Restore <a class="header-anchor" href="#backup-restore" aria-label="Permalink to &quot;Backup &amp; Restore&quot;">​</a></h1><p>RDE provides backup, restore, and migration for system configuration and user data, supporting both cloud server and NAS private deployment scenarios.</p><h2 id="system-configuration-backup" tabindex="-1">System Configuration Backup <a class="header-anchor" href="#system-configuration-backup" aria-label="Permalink to &quot;System Configuration Backup&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Backup Item</th><th>Description</th></tr></thead><tbody><tr><td>RDE App Config</td><td>All module settings and preferences</td></tr><tr><td>User Accounts</td><td>User info, permissions, SSH keys</td></tr><tr><td>Docker Container Config</td><td>docker-compose.yml, env variables (not images)</td></tr><tr><td>Network Config</td><td>DDNS, reverse proxy, port mapping rules</td></tr><tr><td>Scheduled Tasks</td><td>Cron jobs, automation scripts</td></tr><tr><td>Samba Share Config</td><td>Shared directories, access permissions</td></tr></tbody></table><h2 id="user-data-backup" tabindex="-1">User Data Backup <a class="header-anchor" href="#user-data-backup" aria-label="Permalink to &quot;User Data Backup&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Strategy</th></tr></thead><tbody><tr><td>Files/Documents</td><td>Full + incremental backup</td></tr><tr><td>Photo Library</td><td>Including metadata, album structure</td></tr><tr><td>Database</td><td>SQLite export</td></tr><tr><td>App Data Directories</td><td>Selective backup per app</td></tr></tbody></table><h2 id="backup-targets" tabindex="-1">Backup Targets <a class="header-anchor" href="#backup-targets" aria-label="Permalink to &quot;Backup Targets&quot;">​</a></h2><p>Multiple backup targets supported:</p><ul><li><strong>Local disk</strong>: Backup to another partition or external drive</li><li><strong>WebDAV</strong>: Nutstore, ownCloud, etc.</li><li><strong>S3-compatible</strong>: AWS S3, MinIO, Tencent Cloud COS</li><li><strong>SFTP</strong>: Backup to remote server via SSH</li><li><strong>Rclone</strong>: 40+ cloud storage services supported</li></ul><h2 id="backup-strategies" tabindex="-1">Backup Strategies <a class="header-anchor" href="#backup-strategies" aria-label="Permalink to &quot;Backup Strategies&quot;">​</a></h2><ul><li><strong>Manual backup</strong>: Trigger anytime</li><li><strong>Scheduled backup</strong>: Set cron schedules</li><li><strong>Incremental backup</strong>: Only backup changed files, saving space</li><li><strong>Retention policy</strong>: Auto-clean expired backups</li></ul><h2 id="restore" tabindex="-1">Restore <a class="header-anchor" href="#restore" aria-label="Permalink to &quot;Restore&quot;">​</a></h2><ul><li>Restore system configuration from backup files</li><li>Selectively restore specific module data</li><li>Cross-device migration</li></ul><blockquote><p>Premium users can also use cloud backup service for automatic cloud backups.</p></blockquote>',14)])])}const k=e(s,[["render",i]]);export{b as __pageData,k as default};
